// simple_module.c
#include <Python.h>

static PyObject* say_hello(PyObject* self, PyObject* args) {
    return Py_BuildValue("s", "Salam, Dünya!");
}

static PyMethodDef module_methods[] = {
    {"say_hello", say_hello, METH_NOARGS, "Sadə salam funksiyası."},
    {NULL, NULL, 0, NULL}
};

static struct PyModuleDef simple_module = {
    PyModuleDef_HEAD_INIT,
    "simple_module",
    "Sadə C modulu",
    -1,
    module_methods
};

PyMODINIT_FUNC PyInit_simple_module(void) {
    return PyModule_Create(&simple_module);
}

